val photoChannel = Channel<String>() // Создаем канал

// Корутина 1: Качает и отправляет
launch {
    val photos = listOf("photo1.jpg", "photo2.jpg", "photo3.jpg")
    for (photo in photos) {
        photoChannel.send(photo) // Приостановится, если буфер забит
    }
    photoChannel.close() // Закрываем канал, когда данные кончились
}

// Корутина 2: Получает и обрабатывает
launch {
    for (photo in photoChannel) { // Читаем, пока канал не закроют
        saveToDatabase(photo)    // Приостановится, если канал пуст
    }
}
